const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const cors = require('cors');

const app = express();
app.use(cors());
app.use(express.json());

// IMPORTANTE: Usar essa configuração para o Render
const server = http.createServer(app);
const io = socketIo(server, {
  cors: {
    origin: "*", // Em produção, coloque a URL do seu frontend
    methods: ["GET", "POST"],
    credentials: true
  },
  // Necessário para funcionar no Render
  transports: ['websocket', 'polling']
});

// Seu código continua o mesmo...
// (mantenha os event listeners que você já tem)

const PORT = process.env.PORT || 3001;
server.listen(PORT, '0.0.0.0', () => {
  console.log(`🚀 Servidor rodando na porta ${PORT}`);
});